<?php if (!defined('ABSPATH')) exit; $statuses=shakass_request_statuses(); ?>
<div class="wrap sc-admin"><h1>Demandes</h1><?php if($detail): ?><section class="sc-card"><h2>Détail #<?php echo esc_html((string)$detail->ID); ?></h2><?php foreach(['name','email','phone','product','color','size','quantity','estimated_price','message','configuration','preview','created_at'] as $k): $v=get_post_meta($detail->ID,'_shakass_'.$k,true); ?><p><strong><?php echo esc_html($k); ?> :</strong> <?php echo $k==='configuration' ? '<code>'.esc_html($v).'</code>' : esc_html((string)$v); ?></p><?php endforeach; ?><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="shakass_update_request"><input type="hidden" name="request_id" value="<?php echo esc_attr((string)$detail->ID); ?>"><?php wp_nonce_field('shakass_update_request'); ?><label>Statut<select name="status"><?php $cur=get_post_meta($detail->ID,'_shakass_status',true) ?: 'new'; foreach($statuses as $k=>$s) echo '<option value="'.esc_attr($k).'" '.selected($cur,$k,false).'>'.esc_html($s).'</option>'; ?></select></label><button class="button button-primary">Mettre à jour</button></form></section><?php endif; ?><table class="widefat striped"><thead><tr><th>Date</th><th>Nom</th><th>Email</th><th>Téléphone</th><th>Produit</th><th>Quantité</th><th>Prix estimatif</th><th>Statut</th><th></th></tr></thead><tbody><?php foreach($requests as $r): ?><tr><td><?php echo esc_html(get_the_date('', $r)); ?></td><td><?php echo esc_html(get_post_meta($r->ID,'_shakass_name',true)); ?></td><td><?php echo esc_html(get_post_meta($r->ID,'_shakass_email',true)); ?></td><td><?php echo esc_html(get_post_meta($r->ID,'_shakass_phone',true)); ?></td><td><?php echo esc_html(get_post_meta($r->ID,'_shakass_product',true)); ?></td><td><?php echo esc_html(get_post_meta($r->ID,'_shakass_quantity',true)); ?></td><td><?php echo esc_html(get_post_meta($r->ID,'_shakass_estimated_price',true)); ?> €</td><td><?php echo esc_html($statuses[get_post_meta($r->ID,'_shakass_status',true)] ?? 'Nouveau'); ?></td><td><a class="button" href="<?php echo esc_url(admin_url('admin.php?page=shakass-customizer-requests&request_id='.$r->ID)); ?>">Voir détail</a></td></tr><?php endforeach; ?></tbody></table></div>
